SELECT FattureInviateIndicom.SDI, FattureInviateIndicom.[N# documento], FattureInviateIndicom.[Data emissione], FattureInviateIndicom.[Tipo documento], FattureInviateIndicom.[Cedente/prestatore], FattureInviateIndicom.[PIVA Cedente/prestatore], FattureInviateIndicom.[Cessionario/committente], FattureInviateIndicom.[PIVA Cessionario/committente], FattureInviateIndicom.[Codice ufficio], Val([Totale documento]) AS ValoreIndicom, Val([Totale da pagare]) AS DaPagareIndicom, FattureInviateIndicom.Valuta, FattureInviateIndicom.[Codice flusso], FattureInviateIndicom.[Data creazione]
FROM [FattureRegistrateENDC-PerFatturazioneElettronica-step4] INNER JOIN FattureInviateIndicom ON ([FattureRegistrateENDC-PerFatturazioneElettronica-step4].UtlimaDataCreazione = FattureInviateIndicom.[Data creazione]) AND ([FattureRegistrateENDC-PerFatturazioneElettronica-step4].[N# documento] = FattureInviateIndicom.[N# documento]);

